//! Factory functions for creating SVD solvers

use crate::svd::{SvdMethod, SvdSolver, StandardSvd, TruncatedSvd, RandomizedSvd};
use crate::errors::MultivariousError;

/// Create an SVD solver based on the specified method
pub fn create_svd_solver(method: &SvdMethod) -> Result<Box<dyn SvdSolver>, MultivariousError> {
    match method {
        SvdMethod::Full | SvdMethod::Thin => {
            Ok(Box::new(StandardSvd::new()))
        }
        SvdMethod::Truncated(n_components) => {
            Ok(Box::new(TruncatedSvd::new(*n_components)))
        }
        SvdMethod::Randomized { n_components, n_iter, seed } => {
            let mut solver = RandomizedSvd::new(*n_components)
                .with_n_iter(*n_iter);
            if let Some(s) = seed {
                solver = solver.with_seed(*s);
            }
            Ok(Box::new(solver))
        }
    }
}

/// Helper function to select the best SVD method based on matrix size
pub fn select_svd_method(rows: usize, cols: usize, n_components: Option<usize>) -> SvdMethod {
    let min_dim = rows.min(cols);

    match n_components {
        Some(k) if k < min_dim / 2 => {
            // Use randomized SVD for significant dimension reduction
            if rows * cols > 10000 {
                SvdMethod::Randomized {
                    n_components: k,
                    n_iter: 4,
                    seed: None,
                }
            } else {
                SvdMethod::Truncated(k)
            }
        }
        Some(k) if k < min_dim => {
            // Use truncated SVD for moderate dimension reduction
            SvdMethod::Truncated(k)
        }
        _ => {
            // Use thin SVD for full or near-full rank
            if rows != cols {
                SvdMethod::Thin
            } else {
                SvdMethod::Full
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_create_svd_solver() {
        // Test creating standard solver
        let solver = create_svd_solver(&SvdMethod::Full).unwrap();
        assert!(solver.singular_values(&crate::test_utils::test_matrix(5, 3)).is_err());

        // Test creating truncated solver
        let solver = create_svd_solver(&SvdMethod::Truncated(5)).unwrap();
        assert!(solver.singular_values(&crate::test_utils::test_matrix(10, 8)).is_err());

        // Test creating randomized solver
        let solver = create_svd_solver(&SvdMethod::Randomized {
            n_components: 10,
            n_iter: 3,
            seed: Some(42),
        }).unwrap();
        assert!(solver.singular_values(&crate::test_utils::test_matrix(20, 15)).is_err());
    }

    #[test]
    fn test_select_svd_method() {
        // Small matrix, no components specified
        assert!(matches!(
            select_svd_method(10, 5, None),
            SvdMethod::Thin
        ));

        // Square matrix, no components specified
        assert!(matches!(
            select_svd_method(10, 10, None),
            SvdMethod::Full
        ));

        // Small matrix with few components
        assert!(matches!(
            select_svd_method(20, 15, Some(5)),
            SvdMethod::Truncated(5)
        ));

        // Large matrix with few components
        assert!(matches!(
            select_svd_method(200, 150, Some(10)),
            SvdMethod::Randomized { n_components: 10, .. }
        ));

        // Many components requested
        assert!(matches!(
            select_svd_method(20, 15, Some(14)),
            SvdMethod::Truncated(14)
        ));

        // All components requested
        assert!(matches!(
            select_svd_method(20, 15, Some(15)),
            SvdMethod::Thin
        ));
    }
}

